from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Group triples by subject to handle different entities properly
    subject_triples: dict[str, list[Triple]] = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Use the first subject as the main subject
    main_subject = triples[0].subject
    main_clauses: list[str] = []
    related_clauses: list[str] = []

    def get_clause(triple: Triple, is_main: bool = True) -> str:
        p = triple.predicate
        o = triple.object.strip('"')  # remove surrounding quotes if present

        # Map predicates to natural‑language fragments
        if p == "category":
            return f"which is a {o}" if is_main else f"which is a {o}"
        elif p == "country":
            return f"which is in the {o}" if is_main else f"which is in the {o}"
        elif p == "location":
            return f"located in {o}" if is_main else f"located in {o}"
        elif p == "municipality":
            return f"municipality of {o}" if is_main else f"municipality of {o}"
        elif p == "state":
            return f"state of {o}" if is_main else f"state of {o}"
        elif p == "district":
            return f"district of {o}" if is_main else f"district of {o}"
        elif p in ("established", "foundingDate"):
            return f"established on {o}" if is_main else f"established on {o}"
        elif p in ("owner", "owningOrganisation"):
            return f"owned by {o}" if is_main else f"owned by {o}"
        elif p == "inaugurationDate":
            return f"inaugurated on {o}" if is_main else f"inaugurated on {o}"
        elif p == "capital":
            return f"capital is {o}"
        elif p == "legislature":
            return f"legislature is {o}"
        elif p == "dedicatedTo":
            return f"dedicated to {o}" if is_main else f"dedicated to {o}"
        elif p == "designer":
            return f"designed by {o}" if is_main else f"designed by {o}"
        elif p == "material":
            return f"made of {o}" if is_main else f"made of {o}"
        elif p == "ethnicGroup":
            return f"ethnic group is {o}"
        elif p == "language":
            return f"language is {o}"
        elif p == "religion":
            return f"religion is {o}"
        elif p == "nearestCity":
            return f"nearest city is {o}" if is_main else f"nearest city is {o}"
        elif p == "currency":
            return f"currency is {o}"
        elif p == "largestCity":
            return f"largest city is {o}"
        elif p == "leader":
            return f"leader is {o}"
        elif p == "leaderTitle":
            return f"leader title is {o}"
        elif p.startswith("hasToIts"):
            direction = p.replace("hasToIts", "").lower()
            return f"has to its {direction} {o}"
        elif p == "nativeName":
            return f'native name "{o}"' if is_main else f'native name "{o}"'
        else:
            # Fallback for any unexpected predicate
            return f"{o}"

    # Process main subject triples
    for triple in subject_triples.get(main_subject, []):
        main_clauses.append(get_clause(triple, is_main=True))

    # Process related subject triples (like country info)
    for sub, sub_triples in subject_triples.items():
        if sub != main_subject:
            for triple in sub_triples:
                clause = get_clause(triple, is_main=False)
                related_clauses.append(f"{sub} {clause}")

    # Build the sentence - create a more coherent complex sentence
    if main_clauses:
        # Remove duplicate "which is" prefixes for smoother flow
        cleaned_clauses = []
        for i, clause in enumerate(main_clauses):
            if i == 0:
                # First clause keeps subject
                cleaned_clauses.append(clause.lstrip("which is ").lstrip("located "))
            else:
                # Subsequent clauses remove redundant prefixes
                cleaned = clause.lstrip("which is ").lstrip("located ")
                cleaned_clauses.append(cleaned)
        sentence = f"{main_subject} " + ", ".join(cleaned_clauses)
    else:
        sentence = main_subject

    if related_clauses:
        # Add related information as a relative clause for better flow
        sentence += f", where {', '.join(related_clauses)}"

    sentence += "."
    return sentence

# EVOLVE-BLOCK-END

